const input = $('When Executed by Another Workflow').first().json;

const topics = $input.all()
  .filter(item => item.json.id && item.json.title)
  .map(item => ({
    id: item.json.id,
    title: item.json.title
  }));

const messageType = input.message_type || 'text';

const fileAnalysisJson = input.file_analysis_json || {};
const fileAnalysisStatus = input.file_analysis_status || null;
const fileAnalysisSummary =
  input.file_analysis_summary ||
  fileAnalysisJson.summary ||
  null;

const fileAnalysisDetectedType =
  input.file_analysis_detected_type ||
  fileAnalysisJson.detected_type ||
  null;

const parts = [];

if (input.ai_prompt_input) {
  parts.push(input.ai_prompt_input);
}

if (input.file_analysis_text) {
  parts.push(input.file_analysis_text);
}

if (fileAnalysisStatus) {
  parts.push(`File analysis status: ${fileAnalysisStatus}`);
}

if (fileAnalysisSummary) {
  parts.push(`File summary: ${fileAnalysisSummary}`);
}

if (fileAnalysisDetectedType) {
  parts.push(`Detected file type: ${fileAnalysisDetectedType}`);
}

if (Array.isArray(fileAnalysisJson.suggested_topics) && fileAnalysisJson.suggested_topics.length > 0) {
  parts.push(`Suggested topics from file analysis: ${fileAnalysisJson.suggested_topics.join(', ')}`);
}

if (Array.isArray(fileAnalysisJson.keywords) && fileAnalysisJson.keywords.length > 0) {
  parts.push(`File keywords: ${fileAnalysisJson.keywords.join(', ')}`);
}

if (fileAnalysisJson.visible_or_extracted_text) {
  parts.push(`Extracted file text: ${String(fileAnalysisJson.visible_or_extracted_text).slice(0, 2000)}`);
}

if (input.raw_text) {
  parts.push(`Raw text: ${input.raw_text}`);
}

if (input.content) {
  parts.push(`Content: ${input.content}`);
}

if (input.caption) {
  parts.push(`Caption: ${input.caption}`);
}

if (input.file_name) {
  parts.push(`File name: ${input.file_name}`);
}

if (input.mime_type) {
  parts.push(`MIME type: ${input.mime_type}`);
}

if (input.location_title) {
  parts.push(`Location title: ${input.location_title}`);
}

if (input.location_address) {
  parts.push(`Location address: ${input.location_address}`);
}

if (input.maps_url) {
  parts.push(`Map: ${input.maps_url}`);
}

if (parts.length === 0) {
  parts.push(`Message type: ${messageType}`);
}

const messageForAI = parts.join('\n\n');

return [
  {
    json: {
      user_id: input.user_id,
      chat_id: input.chat_id,

      pending_message_id: input.pending_message_id || null,
      message_uuid: input.message_uuid || null,

      message_type: messageType,
      message_for_ai: messageForAI,

      file_analysis_status: fileAnalysisStatus,
      file_analysis_text: input.file_analysis_text || null,
      file_analysis_summary: fileAnalysisSummary,
      file_analysis_detected_type: fileAnalysisDetectedType,
      file_analysis_json: fileAnalysisJson,

      topics
    }
  }
];

const original = $('prepare AI prompt').first().json;

let raw =
  $json.text ||
  $json.ai_raw_text ||
  $json.output ||
  $json.response ||
  $json.message ||
  $json.content ||
  '';

if (!raw && $json.ai_raw_json) {
  raw = JSON.stringify($json.ai_raw_json);
}

if (typeof raw !== 'string') {
  raw = JSON.stringify(raw);
}

raw = String(raw || '')
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let ai;

try {
  ai = JSON.parse(raw);
} catch (e) {
  ai = {
    action: $json.ai_action || 'create_new',
    suggested_topic_id: $json.ai_suggested_topic_id || null,
    suggested_topic_title: $json.ai_suggested_topic_title || null,
    new_topic_title: $json.ai_new_topic_title || 'New Notes',
    summary: $json.ai_summary || null,
    category: $json.ai_category || 'note',
    language: $json.ai_language || 'unknown',
    keywords: $json.ai_keywords || [],
    confidence: Number($json.ai_confidence || 0),
    reason: $json.ai_reason || 'AI classified this message.'
  };
}

const topics = original.topics || [];
const confidence = Number(ai.confidence || 0);
const action = ai.action || 'create_new';

function cleanTopicTitle(title) {
  return String(title || '')
    .replace(/[^\p{L}\p{N}\s&/-]/gu, '')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 40);
}

function normalizeTopic(title) {
  return String(title || '')
    .toLowerCase()
    .replace(/[^\p{L}\p{N}\s]/gu, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function compactSummary(summary) {
  let s = String(summary || '').replace(/\s+/g, ' ').trim();

  const originalText = String(
    original.raw_text ||
    original.content ||
    original.message_for_ai ||
    ''
  ).replace(/\s+/g, ' ').trim();

  const looksLikeOriginal =
    s.length > 300 ||
    (
      originalText.length > 0 &&
      s.length > originalText.length * 0.65
    );

  if (!s || looksLikeOriginal) {
    return '';
  }

  if (s.length > 260) {
    s = s.slice(0, 257) + '...';
  }

  return s;
}

const summary =
  compactSummary(ai.summary) ||
  compactSummary($json.ai_summary) ||
  '';

const keywords = Array.isArray(ai.keywords)
  ? ai.keywords.filter(Boolean).slice(0, 8)
  : [];

const keywordsBlock = keywords.length > 0
  ? `\n\nKeywords: ${keywords.join(', ')}`
  : '';

const aiSummaryBlock = summary
  ? `\n\nAI summary:\n${summary}`
  : '';

const categoryBlock = ai.category
  ? `\n\nCategory: ${ai.category}`
  : '';

function findTopicById(topicId) {
  if (!topicId) return null;
  return topics.find(t => Number(t.id) === Number(topicId)) || null;
}

function findTopicByTitle(title) {
  const normalized = normalizeTopic(title);
  if (!normalized) return null;

  return topics.find(t => normalizeTopic(t.title) === normalized) || null;
}

// Case 1: AI suggests existing topic
if (action === 'use_existing') {
  const topicId = ai.suggested_topic_id ? Number(ai.suggested_topic_id) : null;

  let matchedTopic = findTopicById(topicId);

  if (!matchedTopic && ai.suggested_topic_title) {
    matchedTopic = findTopicByTitle(ai.suggested_topic_title);
  }

  if (matchedTopic && confidence >= 0.5) {
    const reason = ai.reason || 'This looks like the closest matching topic.';

    return [
      {
        json: {
          chat_id: original.chat_id,
          text:
`Suggested topic:

📁 ${matchedTopic.title}

Reason: ${reason}${aiSummaryBlock}${categoryBlock}${keywordsBlock}`,
          inline_keyboard: [
            [
              {
                text: `✅ Save to ${matchedTopic.title}`,
                callback_data: `select_topic:${matchedTopic.id}`
              }
            ],
            [
              {
                text: '📁 Choose another topic',
                callback_data: 'action:choose_topic'
              }
            ],
            [
              {
                text: '➕ Create new topic',
                callback_data: 'action:create_new'
              }
            ],
            [
              {
                text: '❌ Cancel',
                callback_data: 'action:cancel_pending'
              }
            ]
          ]
        }
      }
    ];
  }
}

// Case 2: create new topic
let newTopicTitle =
  cleanTopicTitle(ai.new_topic_title) ||
  cleanTopicTitle(ai.suggested_topic_title) ||
  'New Notes';

const genericTopics = ['new notes', 'notes', 'documents', 'files', 'unsorted notes'];

if (genericTopics.includes(normalizeTopic(newTopicTitle))) {
  if (ai.category === 'recipe') {
    newTopicTitle = 'Recipes';
  } else if (ai.category === 'technical') {
    newTopicTitle = 'Technical Notes';
  } else if (ai.category === 'career') {
    newTopicTitle = 'Career';
  } else if (ai.category === 'finance') {
    newTopicTitle = 'Finance';
  } else if (ai.category === 'legal') {
    newTopicTitle = 'Legal Documents';
  }
}

const reason = ai.reason || 'This would be a useful new topic for this message.';

return [
  {
    json: {
      chat_id: original.chat_id,
      text:
`Suggested new topic:

📁 ${newTopicTitle}

Reason: ${reason}${aiSummaryBlock}${categoryBlock}${keywordsBlock}

Create this topic and save the message here?`,
      inline_keyboard: [
        [
          {
            text: `✅ Create "${newTopicTitle}"`,
            callback_data: `ai_create_topic:${encodeURIComponent(newTopicTitle)}`
          }
        ],
        [
          {
            text: '📁 Choose existing topic',
            callback_data: 'action:choose_topic'
          }
        ],
        [
          {
            text: '➕ Create manually',
            callback_data: 'action:create_new'
          }
        ],
        [
          {
            text: '❌ Cancel',
            callback_data: 'action:cancel_pending'
          }
        ]
      ]
    }
  }
];

