const original = $input.first().json;

const topics = original.topics || [];
const analysis = original.file_analysis_json || {};

const summary = analysis.summary || original.file_analysis_summary || '';
const detectedType = analysis.detected_type || original.file_analysis_detected_type || '';
const suggestedTopics = Array.isArray(analysis.suggested_topics)
  ? analysis.suggested_topics.filter(Boolean)
  : [];

const keywords = Array.isArray(analysis.keywords)
  ? analysis.keywords.filter(Boolean).slice(0, 8)
  : [];

function cleanTopicTitle(title) {
  return String(title || '')
    .replace(/[^\p{L}\p{N}\s&/-]/gu, '')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 40);
}

function normalizeTopic(title) {
  return String(title || '')
    .toLowerCase()
    .replace(/[^\p{L}\p{N}\s]/gu, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function findExistingTopicByNames(names) {
  const normalizedNames = names.map(normalizeTopic).filter(Boolean);

  return topics.find(topic => {
    const normalizedTitle = normalizeTopic(topic.title);
    return normalizedNames.some(name => normalizedTitle === name);
  });
}

function isResumeLike() {
  const combined = [
    detectedType,
    summary,
    suggestedTopics.join(' '),
    keywords.join(' ')
  ]
    .filter(Boolean)
    .join(' ')
    .toLowerCase();

  return (
    combined.includes('resume') ||
    combined.includes('cv') ||
    combined.includes('curriculum vitae') ||
    combined.includes('career') ||
    combined.includes('job') ||
    combined.includes('professional profile') ||
    combined.includes('interview')
  );
}

let preferredTopicNames = [];

// Strong rules by detected type
if (isResumeLike()) {
  preferredTopicNames = ['Resume', 'Career', 'Jobs', 'Interviews', 'Documents'];
} else if (detectedType) {
  const typeMap = {
    receipt: ['Receipts', 'Payments', 'Finance'],
    invoice: ['Invoices', 'Payments', 'Finance'],
    contract: ['Contracts', 'Legal Documents', 'Documents'],
    legal_document: ['Legal Documents', 'Contracts', 'Documents'],
    tax_document: ['Taxes', 'Finance', 'Documents'],
    bank_document: ['Bank Documents', 'Finance', 'Documents'],
    report: ['Reports', 'Analytics', 'Documents'],
    pdf_document: ['Documents'],
    text_document: ['Documents'],
    photo: ['Photos'],
    screenshot: ['Screenshots', 'Photos'],
    travel_document: ['Travel', 'Documents'],
    product: ['Products', 'Shopping'],
    place: ['Places', 'Travel']
  };

  preferredTopicNames = typeMap[detectedType] || [];
}

// Add AI suggested topics after strong rules
preferredTopicNames = [
  ...preferredTopicNames,
  ...suggestedTopics
]
  .map(cleanTopicTitle)
  .filter(Boolean);

// Fallback
if (preferredTopicNames.length === 0) {
  preferredTopicNames = ['Documents'];
}

const existingTopic = findExistingTopicByNames(preferredTopicNames);

const aiSummaryBlock = summary
  ? `\n\nAI summary:\n${summary}`
  : '';

const detectedTypeBlock = detectedType
  ? `\n\nDetected type: ${detectedType}`
  : '';

const suggestedTopicsBlock = suggestedTopics.length > 0
  ? `\n\nAI suggested topics: ${suggestedTopics.join(', ')}`
  : '';

const keywordsBlock = keywords.length > 0
  ? `\n\nKeywords: ${keywords.join(', ')}`
  : '';

if (existingTopic) {
  return [
    {
      json: {
        chat_id: original.chat_id,
        text:
`Suggested topic:

📁 ${existingTopic.title}

Reason: I used the file analysis result to choose the most relevant existing topic.${aiSummaryBlock}${detectedTypeBlock}${suggestedTopicsBlock}${keywordsBlock}`,
        inline_keyboard: [
          [
            {
              text: `✅ Save to ${existingTopic.title}`,
              callback_data: `select_topic:${existingTopic.id}`
            }
          ],
          [
            {
              text: '📁 Choose another topic',
              callback_data: 'action:choose_topic'
            }
          ],
          [
            {
              text: '➕ Create new topic',
              callback_data: 'action:create_new'
            }
          ],
          [
            {
              text: '❌ Cancel',
              callback_data: 'action:cancel_pending'
            }
          ]
        ]
      }
    }
  ];
}

const newTopicTitle = cleanTopicTitle(preferredTopicNames[0]) || 'Documents';

return [
  {
    json: {
      chat_id: original.chat_id,
      text:
`Suggested new topic:

📁 ${newTopicTitle}

Reason: I used the file analysis result to suggest this topic.${aiSummaryBlock}${detectedTypeBlock}${suggestedTopicsBlock}${keywordsBlock}

Create this topic and save the message here?`,
      inline_keyboard: [
        [
          {
            text: `✅ Create "${newTopicTitle}"`,
            callback_data: `ai_create_topic:${encodeURIComponent(newTopicTitle)}`
          }
        ],
        [
          {
            text: '📁 Choose existing topic',
            callback_data: 'action:choose_topic'
          }
        ],
        [
          {
            text: '➕ Create manually',
            callback_data: 'action:create_new'
          }
        ],
        [
          {
            text: '❌ Cancel',
            callback_data: 'action:cancel_pending'
          }
        ]
      ]
    }
  }
];

const original = $('prepare AI prompt').first().json;

// Read AI output from common n8n / LangChain fields
let raw =
  $json.text ||
  $json.output ||
  $json.response ||
  $json.message ||
  $json.content ||
  $json.answer ||
  '';

if (!raw && $json.generations?.[0]?.[0]?.text) {
  raw = $json.generations[0][0].text;
}

if (!raw && $json.data) {
  raw = $json.data;
}

if (typeof raw !== 'string') {
  raw = JSON.stringify(raw);
}

raw = String(raw || '')
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let ai;

try {
  ai = JSON.parse(raw);
} catch (e) {
  const match = raw.match(/\{[\s\S]*\}/);

  if (match) {
    try {
      ai = JSON.parse(match[0]);
    } catch (e2) {
      ai = null;
    }
  }

  if (!ai) {
    ai = {
      action: 'create_new',
      suggested_topic_id: null,
      suggested_topic_title: null,
      new_topic_title: 'New Notes',
      summary: null,
      category: 'note',
      language: 'unknown',
      keywords: [],
      confidence: 0,
      reason: 'Could not parse AI classification response.',
      parse_error: e.message,
      raw_response: raw
    };
  }
}

const messageText =
  original.raw_text ||
  original.content ||
  original.message_for_ai ||
  '';

const keywords = Array.isArray(ai.keywords)
  ? ai.keywords.filter(Boolean).map(String).slice(0, 12)
  : [];

let summary = ai.summary ? String(ai.summary).trim() : '';

// Protect against AI returning the whole original message as summary
const normalizedSummary = summary.replace(/\s+/g, ' ').trim();
const normalizedMessage = String(messageText || '').replace(/\s+/g, ' ').trim();

const summaryLooksLikeOriginal =
  normalizedSummary.length > 300 ||
  (
    normalizedMessage.length > 0 &&
    normalizedSummary.length > normalizedMessage.length * 0.65
  );

if (!summary || summaryLooksLikeOriginal) {
  const categoryGuess = ai.category || ai.detected_type || 'note';

  if (categoryGuess === 'recipe') {
    summary = 'Short cooking note with ingredients and preparation steps.';
  } else if (categoryGuess === 'technical') {
    summary = 'Technical note with practical implementation details.';
  } else if (categoryGuess === 'career') {
    summary = 'Career-related note with professional details.';
  } else if (categoryGuess === 'finance') {
    summary = 'Finance-related note with useful details for tracking.';
  } else if (categoryGuess === 'legal') {
    summary = 'Legal or agreement-related note with important details.';
  } else {
    summary = normalizedMessage
      ? normalizedMessage.slice(0, 180)
      : 'Text message';
  }
}

const category = String(
  ai.category ||
  ai.detected_type ||
  'note'
).trim();

const language = String(
  ai.language ||
  'unknown'
).trim();

const confidence = Number(ai.confidence || 0);

const action = ai.action || 'create_new';

const suggestedTopicTitle =
  ai.suggested_topic_title ||
  ai.new_topic_title ||
  null;

const suggestedTopics = suggestedTopicTitle
  ? [String(suggestedTopicTitle)]
  : [];

const importantDetails = [
  {
    label: 'reason',
    value: ai.reason || 'AI classified this message.'
  },
  {
    label: 'action',
    value: action
  }
];

if (suggestedTopicTitle) {
  importantDetails.push({
    label: 'suggested_topic',
    value: suggestedTopicTitle
  });
}

const normalizedAi = {
  action,
  suggested_topic_id: ai.suggested_topic_id || null,
  suggested_topic_title: ai.suggested_topic_title || null,
  new_topic_title: ai.new_topic_title || null,
  summary,
  category,
  language,
  keywords,
  suggested_topics: suggestedTopics,
  important_details: importantDetails,
  confidence,
  reason: ai.reason || 'AI classified this message.'
};

return [
  {
    json: {
      ...original,

      ai_action: normalizedAi.action,
      ai_suggested_topic_id: normalizedAi.suggested_topic_id,
      ai_suggested_topic_title: normalizedAi.suggested_topic_title,
      ai_new_topic_title: normalizedAi.new_topic_title,

      ai_summary: normalizedAi.summary,
      ai_category: normalizedAi.category,
      ai_language: normalizedAi.language,
      ai_keywords: normalizedAi.keywords,
      ai_suggested_topics: normalizedAi.suggested_topics,
      ai_important_details: normalizedAi.important_details,
      ai_confidence: normalizedAi.confidence,
      ai_reason: normalizedAi.reason,

      ai_raw_json: normalizedAi,
      ai_raw_text: JSON.stringify(normalizedAi),

      text: JSON.stringify(normalizedAi)
    }
  }
];
